import styles from "./page.module.css";

const questions = [
    {
        question: "Est-ce que tu as déjà léché les pieds d'Hady ?",
        reponses: ["Oui", "Non"],
    },
    {
        question: "est-ce que tu as déjà demander a nassim de te faire un virement ?",
        reponses: ["Oui", "Non"],
    },
    {
        question: "est-ce que tu t'es déja excusé seulement dans le but de ne pas te faire ban ?",
        reponses: ["Oui", "Non"],
    },
    {
        question: "es-tu jaloux(se) de la relation entre nassim et meissa ?",
        reponses: ["Oui", "Non"],
    },
];

import { useState } from "react";

export default function Test() {
    const [current, setCurrent] = useState(0);
    const [finished, setFinished] = useState(false);

    const handleAnswer = () => {
        if (current < questions.length - 1) {
            setCurrent(current + 1);
        } else {
            setFinished(true);
        }
    };

    return (
        <div className={styles.page}>
            <div className={styles.header}></div>
            <div>
                {!finished ? (
                    <div className={styles.card}>
                        <div className={styles.top}>
                            <p className={styles.numero}>{current + 1}</p>
                            <h3 className={styles.title}>{questions[current].question}</h3>
                        </div>
                        <div className={styles.buttons}>
                            {questions[current].reponses.map((rep, i) => (
                                <button
                                    key={i}
                                    className={i === 0 ? styles.yes : styles.no}
                                    onClick={handleAnswer}
                                >
                                    {rep}
                                </button>
                            ))}
                        </div>
                    </div>
                ) : (
                    <div className={styles.card}>
                        <h3 className={styles.title}>Merci d'avoir répondu à toutes les questions !</h3>
                    </div>
                )}
            </div>
        </div>
    );
}